```rust
#![no_std]
#![no_main]

use cortex_m_rt::entry;
use stm32f1xx_hal as hal;
use hal::{gpio::{Output, PushPull}, pac};

#[entry]
fn main() -> ! {
    let cp = cortex_m_rt::CorePeripherals::take().unwrap();
    let dp = pac::Peripherals::take().unwrap();

    // Initialize clocks, GPIOC pin 13 as output
    let mut rcc = dp.RCC.constrain();
    let gpio_c = dp.GPIOC.split(&mut rcc.apb2);
    let led = gpio_c.pc13.into_push_pull_output(&mut gpio_c.crh);

    loop {
        led.set_high().unwrap();
        cortex_m::asm::delay(cp.SYST.main_count_down_hz(8_000_000));
        led.set_low().unwrap();
        cortex_m::asm::delay(cp.SYST.main_count_down_hz(8_000_000));
    }
}
```

This uses `cortex-m-rt` for startup code, `stm32f1xx-hal` for HAL traits, and abstracts away register manipulation.
